/**
 * Parses a duration string into milliseconds (ms), seconds (s), minutes (m), hours (h), or days (d).
 * 
 * @param {string} str - The duration string to parse.
 * @returns {number} The parsed duration in milliseconds, rounded to the nearest integer.
 * 
 * @throws {Error} If the input string is not a valid duration format.
 */
function parseDuration(str) {
  const m = /^(\d+(?:\.\d+)?)(ms|s|m|h|d)$/.exec(str.trim());
  if (!m) throw new Error('Invalid duration: ' + str);

  const n = parseFloat(m[1]);
  const u = m[2];
  const mult = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 }[u];
  return Math.round(n * mult);
}

// Usage example
const duration = parseDuration('2.5s'); // Returns 2500 ms
```


